read_verilog -icells -formal <<EOF
module uut;
    wire [7:0] a = $anyconst, b = $anyconst, y;

    \$divfloor #(
        .A_WIDTH(8),
        .B_WIDTH(8),
        .Y_WIDTH(8),
        .A_SIGNED(0),
        .B_SIGNED(0),
    ) divfloor (
        .A(a),
        .B(b),
        .Y(y)
    );

    always @* begin
        assume(b == 4);
        assert(a >> 2 == y);
    end
endmodule
EOF
prep
